import React, { useState } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { useTema } from '../context/TemaContext';

const Navbar = ({ dark }) => {
  const [menuOpen, setMenuOpen] = useState(false);
  const { pathname } = useLocation();

  const toggleMenu = () => setMenuOpen((prev) => !prev);
  const closeMenu = () => setMenuOpen(false);

  const links = dark
    ? [
        { to: '/', label: 'Inicio', icon: 'fa-home' },
        { to: '/ciberseguridad', label: 'Ciberseguridad', icon: 'fa-lock' },
        { to: '/ciberseguridad#amenazas', label: 'Amenazas', icon: 'fa-bug' },
        { to: '/ciberseguridad#herramientas', label: 'Herramientas', icon: 'fa-toolbox' },
        { to: '/ciberseguridad#recursos', label: 'Recursos', icon: 'fa-book' },
        { to: '/ciberseguridad#contacto', label: 'Contacto', icon: 'fa-envelope' }
      ]
    : [
        { to: '/', label: 'Inicio', icon: 'fa-home' },
        { to: '/ciberseguridad', label: 'Ciberseguridad', icon: 'fa-lock' },
        { to: '/#servicios', label: 'Servicios', icon: 'fa-cogs' },
        { to: '/#ceo', label: 'CEO', icon: 'fa-user-tie' },
        { to: '/#galeria', label: 'Clientes', icon: 'fa-images' },
        { to: '/#contacto', label: 'Contacto', icon: 'fa-envelope' }
      ];

  const isActive = (to) => {
    if (to.startsWith('/#')) return pathname === '/' ? 'active' : '';
    return pathname === to ? 'active' : '';
  };

  return (
    <nav className={`navbar ${dark ? 'navbar-dark' : ''}`}>
      <div className="container">
        <div className="logo">
          <i className="fas fa-shield-alt"></i>
          <Link to="/">BlackCat Cibersecurity</Link>
        </div>
        <input
          type="checkbox"
          className="menu-toggle"
          checked={menuOpen}
          onChange={toggleMenu}
        />
        <label className="menu-icon" onClick={toggleMenu}>
          <span></span>
          <span></span>
          <span></span>
        </label>
        <ul className="nav-menu">
          {links.map((link) => (
            <li key={link.to}>
              <Link to={link.to} className={isActive(link.to)} onClick={closeMenu}>
                <i className={`fas ${link.icon}`}></i> {link.label}
              </Link>
            </li>
          ))}
        </ul>
      </div>
    </nav>
  );
};

export default Navbar;
